diff --git a/tests/formatters_boundaries.test.ts b/tests/formatters_boundaries.test.ts
new file mode 100644
index 0000000..1e02b70
--- /dev/null
+++ b/tests/formatters_boundaries.test.ts
@@ -0,0 +1,113 @@
+/**
+ * Boundary / edge-case correctness for the native trading display formatters.
+ *
+ * These assert the correct outputs on the exact-threshold and edge inputs that
+ * the broader display-formatter suite never exercises: a value sitting exactly
+ * on the compact-number K cutoff, a wallet address exactly at the abbreviation
+ * floor, an email string with trailing content after an otherwise well-formed
+ * address, a phone number of exactly the canonical digit length, and a crypto
+ * amount sitting exactly on a precision-band boundary. The existing tests only
+ * ever feed values comfortably away from these edges, so a boundary regression
+ * here stays invisible to them.
+ */
+
+import { describe, expect, test } from 'bun:test';
+import {
+	formatAddress,
+	formatCompactNumber,
+	formatCryptoAmount,
+	isValidEmail,
+	isValidPhone,
+} from '../lib/formatters';
+
+describe('formatters boundary behavior', () => {
+	// ---- fail_to_pass: exact-edge inputs the visible suite never feeds ----
+
+	test('compact number promotes exactly one thousand to K', () => {
+		// 1000 is the smallest value that is "a thousand"; the K bucket must
+		// include its own lower bound, exactly as the M and B buckets do.
+		expect(formatCompactNumber(1_000)).toBe('1.00K');
+	});
+
+	test('address exactly at the abbreviation floor is left intact', () => {
+		// When the address is only as long as the two visible windows combined,
+		// abbreviating it would not shorten it, so it must be returned whole.
+		expect(formatAddress('0x123456', 4)).toBe('0x123456');
+	});
+
+	test('email with trailing content after the domain is rejected', () => {
+		// A well-formed address followed by extra text is not a valid email;
+		// validation must reject the whole string, not just accept its prefix.
+		expect(isValidEmail('user@example.com not-real')).toBe(false);
+	});
+
+	test('phone at exactly the canonical ten-digit length is accepted', () => {
+		// A bare ten-digit number is the canonical phone the app formats; the
+		// minimum-length gate must include ten, not require more than ten.
+		expect(isValidPhone('5551234567')).toBe(true);
+	});
+
+	test('crypto amount exactly on the small-value boundary keeps four decimals', () => {
+		// 0.01 is not below the very-small cutoff; it falls in the next band
+		// down, which renders four decimals, matching the sibling boundary form.
+		expect(formatCryptoAmount(0.01, 'BTC')).toBe('0.0100 BTC');
+	});
+
+	// ---- pass_to_pass: values comfortably away from every edge ----
+
+	test('compact number formats a mid-range thousands value', () => {
+		expect(formatCompactNumber(1_500)).toBe('1.50K');
+	});
+
+	test('compact number formats a millions value', () => {
+		expect(formatCompactNumber(2_500_000)).toBe('2.50M');
+	});
+
+	test('compact number formats a billions value', () => {
+		expect(formatCompactNumber(3_000_000_000)).toBe('3.00B');
+	});
+
+	test('compact number leaves sub-thousand values unscaled', () => {
+		expect(formatCompactNumber(999)).toBe('999.00');
+	});
+
+	test('address well above the floor is abbreviated at both ends', () => {
+		expect(formatAddress('0x1234567890abcdef', 4)).toBe('0x12...cdef');
+	});
+
+	test('address well below the floor is returned unchanged', () => {
+		expect(formatAddress('short', 4)).toBe('short');
+	});
+
+	test('a well-formed email is accepted', () => {
+		expect(isValidEmail('investor@example.com')).toBe(true);
+	});
+
+	test('a string missing the at-sign is rejected', () => {
+		expect(isValidEmail('investor.example.com')).toBe(false);
+	});
+
+	test('a spaced international phone well over ten digits is accepted', () => {
+		expect(isValidPhone('+230 5123 4567')).toBe(true);
+	});
+
+	test('a short numeric string well under ten digits is rejected', () => {
+		expect(isValidPhone('12345')).toBe(false);
+	});
+
+	test('a three-digit string is rejected as a phone', () => {
+		expect(isValidPhone('123')).toBe(false);
+	});
+
+	test('crypto amount well below the small cutoff uses maximum precision', () => {
+		expect(formatCryptoAmount(0.00001234, 'BTC')).toBe('0.00001234 BTC');
+	});
+
+	test('crypto amount in the sub-unit band uses four decimals', () => {
+		expect(formatCryptoAmount(0.125, 'ETH')).toBe('0.1250 ETH');
+	});
+
+	test('crypto amount at or above one unit uses minimum decimals', () => {
+		expect(formatCryptoAmount(12.5, 'SOL')).toBe('12.50 SOL');
+	});
+});
